INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES
(8, 1, '09', '티커 개념', '문서에서 티커(Ticker)의 유래로 설명된 것은?', '전신 부호를 숫자로 변환한 시스템', '종이 띠(Ticker Tape)에 짧은 알파벳 기호로 주식 시세를 표시하던 관행', '컴퓨터 데이터베이스에서 기업 ID를 부여하는 방식', '금융감독원이 상장 기업에 부여하는 고유 번호', 2, '문서에서 과거 주식 시세를 종이 띠(Ticker Tape)에 인쇄할 때 회사 이름 대신 짧은 알파벳 기호로 표시하던 습관에서 티커가 유래되었다고 설명합니다.'),
(8, 2, '09', '티커 개념', '문서에서 한국의 티커(종목코드) 형태로 제시된 것은?', '영문 알파벳 대문자 4자리', '숫자 6자리', '영문+숫자 혼합 8자리', '거래소 코드 + 영문 3자리', 2, '문서에서 한국은 티커 대신 "종목코드"라고 부르며 6자리 숫자로 구성된다고 설명합니다. 예시로 삼성전자(005930), NAVER(035420)가 제시됩니다.'),
(8, 3, '09', '티커 개념', '문서에서 삼성전자의 종목코드로 제시된 것은?', '373220', '035420', '005930', '000660', 3, '문서에서 삼성전자의 종목코드는 005930으로 제시됩니다. 035420은 NAVER, 373220은 LG에너지솔루션의 코드입니다.'),
(8, 4, '09', '티커 개념', '문서에서 티커 사용의 장점 중 "정확성"에 해당하는 설명은?', '전 세계 투자자와 시스템이 동일한 기호를 사용한다', '짧은 코드를 입력해 빠르게 검색 및 매매할 수 있다', '이름이 유사한 기업 간의 혼동을 방지한다', 'HTS·MTS에서 가장 정확한 검색 결과를 얻을 수 있다', 3, '문서 티커 사용의 장점 항목에서 "정확성"은 이름이 유사한 기업 간의 혼동을 방지한다고 설명합니다.'),
(8, 5, '09', 'PER 개념', '문서에서 PER(주가수익비율)의 계산 공식으로 제시된 것은?', 'PER = 주가 / 주당순자산(BPS)', 'PER = 시가총액 / 매출액', 'PER = 주가 / 주당순이익(EPS)', 'PER = 기업가치(EV) / EBITDA', 3, '문서에서 PER = 주가 / 주당순이익(EPS) = 시가총액 / 당기순이익으로 정의됩니다.'),
(8, 6, '09', 'PER 개념', '문서에서 "PER 20배"의 의미로 제시된 설명은?', '주가가 순자산의 20배임을 의미한다', '지금 이익 수준이라면 20년이 지나야 투자금을 회수한다는 뜻이다', '매출액 대비 시가총액이 20배임을 의미한다', '기업가치가 EBITDA의 20배임을 의미한다', 2, '문서에서 PER 20배는 지금 이익 수준이라면 20년이 지나야 투자금을 회수한다는 뜻이라고 설명합니다.'),
(8, 7, '09', 'PER 개념', '문서에서 높은 PER의 해석으로 제시된 것은?', '재무 위험이 크거나 부실 기업임을 나타낸다', '저평가이거나 성장 정체·위험이 반영된 것이다', '시장이 미래 고성장을 기대하는 상태이다', '배당 수익률이 높은 성숙 기업임을 나타낸다', 3, '문서에서 높은 PER은 시장이 미래 고성장을 기대하는 상태를 나타내고, 낮은 PER은 저평가이거나 성장 정체·위험 반영이라고 설명합니다.'),
(8, 8, '09', 'PER 개념', '문서에서 PER 계산이 불가능한 경우와 왜곡 원인으로 제시된 것은?', '부채가 많은 기업, 자산 재평가 시 왜곡', '적자 기업에는 PER 계산 불가, 일회성 이익이 섞이면 왜곡', '매출 성장 기업은 PER 적용 불가, 감가상각 크면 왜곡', '금융업은 PER 계산 불가, 외화 손익이 섞이면 왜곡', 2, '문서에서 적자 기업에는 PER 계산이 불가하고, 일회성 이익이 섞이면 PER이 왜곡될 수 있다고 설명합니다.'),
(8, 9, '09', 'PBR·EV/EBITDA·PSR', '문서에서 PBR(주가순자산비율)이 유용한 업종으로 제시된 것은?', '초기 성장 기업, 바이오', '반도체, 사이클 업종', '은행, 부동산 등 자산 중심 업종', '플랫폼·IT 고성장 기업', 3, '문서 멀티플 표에서 PBR은 주가 / 주당순자산(BPS)으로 자산 중심 업종(은행, 부동산), 해산 가치 비교 시 유용하다고 설명합니다.'),
(8, 10, '09', 'PBR·EV/EBITDA·PSR', '문서에서 PSR(주가매출비율)이 유용한 경우로 제시된 것은?', '부채 구조 비교, 인수합병 가치 평가 시', '자산 중심 업종, 해산 가치 비교 시', '안정적 이익이 있는 소비재·유통 업종', '적자 성장 기업, 매출이 핵심인 초기 기업', 4, '문서 멀티플 표에서 PSR(시가총액 / 매출액)은 적자 성장 기업, 매출이 핵심인 초기 기업에 유용하다고 설명합니다.'),
(8, 11, '09', 'PBR·EV/EBITDA·PSR', '문서에서 EV/EBITDA의 공식으로 제시된 것은?', '시가총액 / 영업이익', '주가 / 주당순자산(BPS)', '기업가치(EV) / EBITDA', '시가총액 / 당기순이익', 3, '문서 멀티플 표에서 EV/EBITDA = 기업가치(EV) / EBITDA로 정의되며, 부채 구조 비교 및 인수합병 가치 평가 시 유용하다고 설명합니다.'),
(8, 12, '09', 'PBR·EV/EBITDA·PSR', '문서의 EV/EBITDA 코드 예시에서 A사(무차입)와 B사(고차입)의 시가총액이 동일할 때 EV/EBITDA에 대한 설명은?', '두 회사의 EV/EBITDA는 동일하다', 'A사(무차입)의 EV/EBITDA가 B사(고차입)보다 훨씬 높다', 'B사(고차입)의 EV/EBITDA가 A사(무차입)보다 훨씬 높다', '차입 구조는 EV/EBITDA에 영향을 미치지 않는다', 3, '문서 EV/EBITDA 코드 예시에서 시가총액이 같아도 고차입 B사(18.1배)가 무차입 A사(10.6배)보다 EV/EBITDA가 훨씬 높게 나온다고 설명합니다.'),
(8, 13, '09', 'PBR·EV/EBITDA·PSR', '문서에서 이익이 불안정한 기업에 PER 대신 권장하는 멀티플은?', 'PBR 또는 배당수익률', 'PSR 또는 EV/EBITDA', 'ROE 또는 부채비율', 'Forward PER 또는 PEG', 2, '문서에서 이익이 불안정한 기업은 PER보다 PSR이나 EV/EBITDA가 더 유용할 수 있다고 설명합니다.'),
(8, 14, '09', '업종별 멀티플', '문서에서 은행·금융 업종에 주로 사용하는 멀티플과 대략적 범위는?', 'PER, 10~20배', 'EV/EBITDA, 10~25배', 'PBR, 0.5~1.5배', 'PSR, 적자라 PER 미사용', 3, '문서 업종별 적정 멀티플 기준 표에서 은행·금융은 자산 가치 중심이므로 PBR을 주로 사용하며 대략적 범위는 0.5~1.5배라고 설명합니다.'),
(8, 15, '09', '업종별 멀티플', '문서에서 반도체 업종에 주로 사용하는 멀티플과 대략적 범위는?', 'PBR, 0.5~1.5배', 'EV/EBITDA, 10~25배', 'PER 또는 PSR, 20~50배+', 'PSR, 적자라 PER 미사용', 2, '문서 업종별 적정 멀티플 기준 표에서 반도체는 사이클 평탄화 목적으로 EV/EBITDA를 사용하며 대략적 범위는 10~25배라고 설명합니다.'),
(8, 16, '09', '업종별 멀티플', '문서에서 바이오 업종에 주로 사용하는 멀티플과 이유는?', 'PER, 안정적 이익이 있기 때문', 'PBR, 자산 가치 중심이기 때문', 'EV/EBITDA, 부채 구조 비교 목적', 'PSR, 적자라 PER 미사용', 4, '문서 업종별 적정 멀티플 기준 표에서 바이오는 적자 기업이 많아 PER을 미사용하고 PSR(주가매출비율)을 주로 활용한다고 설명합니다.'),
(8, 17, '09', '업종별 멀티플', '문서에서 멀티플이 낮다고 무조건 저평가가 아닌 이유로 제시된 것은?', '미래 성장률이 이미 주가에 반영되어 있기 때문', '성장 둔화나 재무 위험이 반영된 결과일 수도 있기 때문', '동일 업종 내 비교가 아니면 의미가 없기 때문', 'EPS가 일회성 이익으로 부풀려진 경우가 많기 때문', 2, '문서에서 멀티플이 낮다고 무조건 저평가가 아니라, 성장 둔화나 재무 위험이 반영된 결과일 수도 있다고 설명합니다.'),
(8, 18, '09', '업종별 멀티플', '문서의 멀티플 선택 프로세스에서 이익이 흑자이고 자산 집약 업종(은행·부동산)인 경우 적용하는 멀티플은?', 'PSR', 'PER + PEG 병행', 'PBR', 'EV/EBITDA', 3, '문서 업종별 멀티플 선택 flowchart에서 이익이 흑자이고 자산 집약 업종(은행·부동산·보험)인 경우 PBR을 적용해 자산 해산가치를 비교한다고 설명합니다.'),
(8, 19, '09', '멀티플 스크리닝', '문서에서 멀티플 스크리닝의 정의로 제시된 것은?', '재무제표를 분기별로 상세 분석하는 과정', '많은 종목 중에서 원하는 조건에 맞는 후보를 빠르게 추리는 과정', '특정 기업의 DCF 내재가치를 계산하는 방법', '업종별 멀티플 평균을 계산하는 통계 기법', 2, '문서에서 스크리닝은 많은 종목 중에서 원하는 조건에 맞는 후보를 빠르게 추리는 과정이라고 설명합니다.'),
(8, 20, '09', '멀티플 스크리닝', '문서의 screen_multiples 함수에서 필터 조건을 None으로 전달하면 어떻게 되는가?', '기본값(Default)으로 자동 대체된다', '해당 필터는 건너뛴다(적용 안 함)', '오류가 발생한다', '모든 데이터가 필터링되어 빈 결과가 반환된다', 2, '문서 screen_multiples 함수 주석에서 "조건을 None으로 전달하면 해당 필터는 건너뜁니다"라고 명시합니다.'),
(8, 21, '09', '멀티플 스크리닝', '문서의 비교 체크리스트에서 EV/EBITDA 해석에 직접 영향을 미치는 항목은?', '일회성 이익/손실', '성장률 차이', '부채 구조', '현금흐름과 Capex', 3, '문서 기업가치 분석용 비교 체크리스트에서 부채 구조가 EV/EBITDA 해석에 직접 영향을 미친다고 설명하며, 차입 급증 기업은 EV가 빠르게 높아질 수 있다고 언급합니다.'),
(8, 22, '09', '멀티플 스크리닝', '문서의 스크리닝 조건 선택 가이드에서 "가치주 발굴"의 핵심 조건은?', '매출성장률 ≥ 15%, Forward PER 확인', 'PER ≤ 업종 평균, PBR ≤ 1.5', 'PBR ≤ 0.7, 부채비율 낮음', 'EV/EBITDA ≤ 8, 순현금 기업', 2, '문서 스크리닝 조건 선택 가이드 표에서 가치주 발굴의 핵심 조건은 PER ≤ 업종 평균, PBR ≤ 1.5라고 제시됩니다.'),
(8, 23, '09', '멀티플 스크리닝', '문서에서 M&A 대상 스크리닝 시 핵심 조건으로 제시된 것은?', 'PER ≤ 업종 평균, PBR ≤ 1.5', '매출성장률 ≥ 15%, Forward PER 확인', 'EV/EBITDA ≤ 8, 순현금 기업', 'PBR ≤ 0.7, 부채비율 낮음', 3, '문서 스크리닝 조건 선택 가이드 표에서 M&A 대상 스크리닝의 핵심 조건은 EV/EBITDA ≤ 8, 순현금 기업이라고 제시됩니다.'),
(8, 24, '09', '데이터 원천', '문서에서 yfinance로 한국 코스피 상장 종목을 조회할 때 티커 형식은?', '종목코드.KRX', '종목코드.KR', '종목코드.KS', '종목코드.KQ', 3, '문서에서 한국 상장 종목은 코스피 .KS, 코스닥 .KQ를 티커에 붙인다고 설명하며, KS는 코스피 종목에 사용합니다.'),
(8, 25, '09', '데이터 원천', '문서에서 yfinance 사용의 장점으로 제시된 것은?', 'DART 공시 원문을 직접 제공해 EPS 오류가 없다', 'KRX 공식 멀티플 통계를 실시간 제공한다', '별도 API Key 없이 바로 사용할 수 있어 실습 진입 장벽이 낮다', '분기 실적 발표와 동시에 PER을 자동 업데이트한다', 3, '문서에서 yfinance는 별도 API Key 없이 바로 사용할 수 있어 실습 진입 장벽이 낮다고 설명합니다.'),
(8, 26, '09', '데이터 품질', '문서에서 같은 종목의 PER이 NAVER Finance와 yfinance에서 다를 수 있는 주요 이유로 제시된 것은?', '환율 적용 기준이 다르기 때문', 'EPS 기준(TTM vs Forward)과 주식 수 처리 방법이 다르기 때문', '시가총액 계산 방식이 근본적으로 다르기 때문', '두 사이트 모두 수동으로 데이터를 입력하기 때문', 2, '문서 유사 정보 비교 표에서 EPS 기준(TTM/Forward), 주식 수 처리(자사주·우선주 포함 여부), 업데이트 주기가 달라 같은 종목의 PER이 사이트마다 다를 수 있다고 설명합니다.'),
(8, 27, '09', '데이터 품질', '문서에서 EV/EBITDA 해석 시 Capex를 함께 봐야 하는 이유는?', '차입 급증 기업은 EV가 빠르게 높아질 수 있기 때문', '설비투자 부담이 큰 업종은 EBITDA가 실제 현금창출력보다 좋아 보일 수 있기 때문', '분기 실적 발표 전후로 EBITDA가 크게 달라질 수 있기 때문', 'yfinance TTM EPS가 부정확할 수 있기 때문', 2, '문서에서 설비투자 부담이 큰 업종은 EBITDA가 실제 현금창출력보다 좋아 보일 수 있으니 Capex도 함께 봐야 한다고 설명합니다.'),
(8, 28, '09', '시각화', '문서에서 ROE vs PBR 산점도에서 "이론선 아래"에 위치한 종목의 의미는?', '고평가 위험 구간에 있는 종목', '저평가 후보로 볼 수 있는 종목', '적자 기업으로 PER 계산 불가', '배당 수익률이 낮은 성장주', 2, '문서 ROE vs PBR 산점도 코드에서 차트 제목을 "ROE vs PBR — 이론선 아래: 저평가 후보"로 표시하며, 이론선(PBR = ROE / 기대수익률) 아래 종목은 저평가 후보로 해석합니다.'),
(8, 29, '09', '시각화', '문서의 멀티플 히트맵에서 색상(Z-score)이 낮을수록(녹색) 나타내는 의미는?', '절대적 고평가 구간', '상대적 저평가 구간', '배당 수익률이 높은 구간', '매출 성장률이 낮은 구간', 2, '문서 멀티플 히트맵 코드에서 cbar_kws={"label": "Z-score (낮을수록 상대적 저평가)"}로 설정되어 있으며, 색상이 낮을수록(녹색) 상대적 저평가를 의미한다고 설명합니다.'),
(8, 30, '09', '데이터 품질', '문서에서 멀티플 보고서에 반드시 표시해야 할 항목으로 제시된 것은?', '목표 주가, 투자 등급, 리스크 요인', '원천·수집일·EPS 기준(TTM/Forward)·결측 처리 방법', '섹터 분류, 비교 대상 기업 수, 필터 조건', '할인율(WACC), 영구성장률, Terminal Value 비중', 2, '문서에서 보고서에는 원천·수집일·EPS 기준(TTM/Forward)·결측 처리 방법을 반드시 표시해야 한다고 설명합니다.');
